using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup() => _sut = new ShoppingCart();

    // ───────────────────────── AddItem ─────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _sut.AddItem("SKU-001", 1, 9.99m);

        Assert.AreEqual(9.99m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleQuantity_MultipliesPrice()
    {
        _sut.AddItem("SKU-001", 3, 10.00m);

        Assert.AreEqual(30.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDifferentItems_SumsAll()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-002", 2, 5.00m);

        Assert.AreEqual(20.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_AccumulatesQuantity()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-001", 2, 10.00m);

        Assert.AreEqual(30.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null SKU")]
    [DataRow("", DisplayName = "Empty SKU")]
    public void AddItem_NullOrEmptySku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem(sku!, 1, 10.00m));
    }

    [TestMethod]
    [DataRow(0, DisplayName = "Zero quantity")]
    [DataRow(-1, DisplayName = "Negative quantity")]
    public void AddItem_InvalidQuantity_ThrowsArgumentOutOfRangeException(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-001", quantity, 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentOutOfRangeException()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-001", 1, -5.00m));
    }

    // ───────────────────────── RemoveItem ─────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _sut.AddItem("SKU-001", 2, 10.00m);
        _sut.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OneOfMultipleItems_KeepsOthers()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-002", 1, 20.00m);

        _sut.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.RemoveItem("MISSING"));
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null SKU")]
    [DataRow("", DisplayName = "Empty SKU")]
    public void RemoveItem_NullOrEmptySku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.RemoveItem(sku!));
    }

    // ───────────────────────── CalculateTotal ─────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsRemainingItems()
    {
        _sut.AddItem("SKU-001", 1, 15.00m);
        _sut.AddItem("SKU-002", 1, 25.00m);
        _sut.RemoveItem("SKU-001");

        Assert.AreEqual(25.00m, _sut.CalculateTotal());
    }

    // ───────────────────────── ApplyCoupon ─────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _sut.AddItem("SKU-001", 1, 100.00m);
        _sut.ApplyCoupon("SAVE10");

        var total = _sut.CalculateTotal();
        Assert.IsTrue(total < 100.00m, $"Expected discounted total but got {total}");
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon("INVALID"));
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null coupon")]
    [DataRow("", DisplayName = "Empty coupon")]
    public void ApplyCoupon_NullOrEmptyCode_ThrowsArgumentException(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_TotalRemainsZero()
    {
        _sut.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_TotalNeverGoesNegative()
    {
        _sut.AddItem("SKU-001", 1, 1.00m);
        _sut.ApplyCoupon("SAVE10");

        var total = _sut.CalculateTotal();
        Assert.IsTrue(total >= 0m, $"Total should never be negative but was {total}");
    }
}

